/*!
 * htmx-lite — a minimal vendored subset of HTMX behavior used by ToolWatch.
 *
 * Supports only:
 *   - hx-get on elements with hx-trigger="change", "submit", or "every Ns"
 *   - hx-target as a CSS selector or "this"
 *   - hx-swap "outerHTML" (default) and "innerHTML"
 *
 * Polling is disabled when the page is hidden. The script is self-contained,
 * defers all execution until the DOM is parsed, and never evaluates returned
 * markup through innerHTML on element types that execute scripts.
 */
(function () {
  "use strict";

  function selectTargets(el) {
    var sel = el.getAttribute("hx-target");
    if (!sel || sel === "this") return [el];
    var found = document.querySelectorAll(sel);
    return found.length ? Array.prototype.slice.call(found) : [el];
  }

  function applySwap(target, html, swap) {
    var doc = new DOMParser().parseFromString(html, "text/html");
    var nodes = Array.prototype.slice.call(doc.body.childNodes);
    if (swap === "innerHTML") {
      target.innerHTML = "";
      nodes.forEach(function (n) {
        target.appendChild(n);
      });
      return target;
    }
    var parent = target.parentNode;
    if (!parent) return target;
    var replacement = null;
    nodes.forEach(function (n) {
      var inserted = parent.insertBefore(n, target);
      if (!replacement && inserted.nodeType === 1) replacement = inserted;
    });
    parent.removeChild(target);
    return replacement || parent;
  }

  function buildUrl(base, params) {
    if (!params) return base;
    var pairs = [];
    Object.keys(params).forEach(function (key) {
      if (params[key] === null || params[key] === undefined || params[key] === "") return;
      pairs.push(encodeURIComponent(key) + "=" + encodeURIComponent(params[key]));
    });
    if (!pairs.length) return base;
    return base + (base.indexOf("?") >= 0 ? "&" : "?") + pairs.join("&");
  }

  function fetchAndSwap(el, params) {
    var url = el.getAttribute("hx-get");
    if (!url) return;
    var swap = el.getAttribute("hx-swap") || "outerHTML";
    var full = buildUrl(url, params);
    fetch(full, {
      credentials: "same-origin",
      headers: { "HX-Request": "true", "Accept": "text/html" },
    })
      .then(function (response) {
        if (!response.ok) return null;
        return response.text();
      })
      .then(function (html) {
        if (html === null) return;
        selectTargets(el).forEach(function (target) {
          applySwap(target, html, swap);
        });
      })
      .catch(function () {
        /* fail open; user can refresh */
      });
  }

  function formParams(form) {
    var data = new FormData(form);
    var params = {};
    data.forEach(function (value, key) {
      if (value === null || value === undefined || value === "") return;
      params[key] = value;
    });
    return params;
  }

  function attachForm(form) {
    var trigger = form.getAttribute("hx-trigger") || "submit";
    var triggers = trigger.split(",").map(function (s) { return s.trim(); });
    if (triggers.indexOf("submit") >= 0) {
      form.addEventListener("submit", function (event) {
        event.preventDefault();
        fetchAndSwap(form, formParams(form));
      });
    }
    if (triggers.indexOf("change") >= 0) {
      form.addEventListener("change", function () {
        fetchAndSwap(form, formParams(form));
      });
    }
  }

  function attachPolling(el) {
    var trigger = el.getAttribute("hx-trigger") || "";
    var match = /^every\s+(\d+)s$/.exec(trigger);
    if (!match) return;
    var interval = parseInt(match[1], 10) * 1000;
    if (!isFinite(interval) || interval < 1000) return;
    var timer = null;
    function tick() {
      if (document.visibilityState === "visible" && el.isConnected) {
        fetchAndSwap(el, null);
      }
    }
    timer = window.setInterval(tick, interval);
    document.addEventListener("visibilitychange", function () {
      // pause/resume implicitly through the visibility guard in tick.
    });
  }

  function init() {
    var elements = document.querySelectorAll("[hx-get], [hx-post]");
    Array.prototype.forEach.call(elements, function (el) {
      if (el.tagName === "FORM") {
        attachForm(el);
      } else {
        attachPolling(el);
      }
    });
  }

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", init);
  } else {
    init();
  }
})();
